248	```ts
249	// Read-only customization scanning shared by providers (Spec: customizations
250	// browser v1). Types + generic helpers only — provider PATHS live in each
251	// provider module (hard rule 3). Every item is file-path addressed: filePath
252	// is the item's identity and v2's edit target (.claude/docs/customizations-roadmap.md).
253	
254	import { createHash } from 'node:crypto';
255	import { readdir, readFile } from 'node:fs/promises';
256	import path from 'node:path';
257	
258	export type CustomizationScope = { kind: 'global' } | { kind: 'project'; repoPath: string };
259	
260	export interface CustomizationItem {
261	  id: string;
262	  provider: 'claude' | 'codex';
263	  scope: 'global' | 'project';
264	  filePath: string;
265	  title: string;
266	  meta: Record<string, string>;
267	  content: string;
268	  parseError?: string;
269	}
270	
271	export interface CustomizationScanners {
272	  agents?(scope: CustomizationScope): Promise<CustomizationItem[]>;
273	  skills?(scope: CustomizationScope): Promise<CustomizationItem[]>;
274	  instructions?(scope: CustomizationScope): Promise<CustomizationItem[]>;
275	  hooks?(scope: CustomizationScope): Promise<CustomizationItem[]>;
276	  mcpServers?(scope: CustomizationScope): Promise<CustomizationItem[]>;
277	}
278	
279	export interface ScanDeps {
280	  homeDir: string;
281	}
282	
283	export function itemId(filePath: string, entryKey = ''): string {
284	  return createHash('sha1').update(filePath + '\0' + entryKey).digest('hex').slice(0, 16);
285	}
286	
287	// Minimal YAML-subset frontmatter parser: `key: value` lines between --- fences.
288	// Good frontmatter in the wild is exactly that shape; anything fancier (nested
289	// yaml) keeps the raw text as body with no error — we render, not validate.
290	export function parseFrontmatter(src: string): { attrs: Record<string, string>; body: string; error?: string } {
291	  if (!src.startsWith('---\n')) return { attrs: {}, body: src };
292	  const end = src.indexOf('\n---', 4);
293	  if (end === -1) return { attrs: {}, body: src, error: 'unterminated frontmatter' };
294	  const attrs: Record<string, string> = {};
295	  for (const line of src.slice(4, end).split('\n')) {
296	    const m = /^([A-Za-z0-9_-]+):\s*(.*)$/.exec(line);
297	    if (m) attrs[m[1]] = m[2].trim();
298	  }
299	  return { attrs, body: src.slice(end + 4).replace(/^\n/, '') };
300	}
301	
302	async function fileToItem(
303	  filePath: string,
304	  provider: 'claude' | 'codex',
305	  scope: 'global' | 'project',
306	): Promise<CustomizationItem> {
307	  const raw = await readFile(filePath, 'utf8');
308	  const fm = parseFrontmatter(raw);
309	  return {
310	    id: itemId(filePath),
311	    provider,
312	    scope,
313	    filePath,
314	    title: fm.attrs.name || path.basename(filePath, '.md'),
315	    meta: fm.attrs,
316	    content: raw,
317	    ...(fm.error ? { parseError: fm.error } : {}),
318	  };
319	}
320	
321	/** Scan a flat dir of *.md files (agents, codex prompts). Missing dir -> []. */
322	export async function scanMarkdownDir(
323	  dir: string,
324	  provider: 'claude' | 'codex',
325	  scope: 'global' | 'project',
326	): Promise<CustomizationItem[]> {
327	  let names: string[];
328	  try {
329	    names = (await readdir(dir)).filter((n) => n.endsWith('.md'));
330	  } catch {
331	    return [];
332	  }
333	  const items = await Promise.all(names.sort().map((n) => fileToItem(path.join(dir, n), provider, scope)));
334	  return items;
335	}
336	
337	/** Scan skills layout: <dir>/<skill-name>/SKILL.md. Missing dir -> []. */
338	export async function scanSkillsDir(
339	  dir: string,
340	  provider: 'claude' | 'codex',
341	  scope: 'global' | 'project',
342	): Promise<CustomizationItem[]> {
343	  let entries: string[];
344	  try {
345	    entries = await readdir(dir);
346	  } catch {
347	    return [];
348	  }
349	  const out: CustomizationItem[] = [];
350	  for (const name of entries.sort()) {
351	    const f = path.join(dir, name, 'SKILL.md');
352	    try {
353	      out.push(await fileToItem(f, provider, scope));
354	    } catch {
355	      /* not a skill dir */
356	    }
357	  }
358	  return out;
359	}
360	
361	/** One item per instruction file that exists. */
362	export async function scanInstructionFiles(
363	  files: string[],
364	  provider: 'claude' | 'codex',
365	  scope: 'global' | 'project',
366	): Promise<CustomizationItem[]> {
367	  const out: CustomizationItem[] = [];
368	  for (const f of files) {
369	    try {
370	      const raw = await readFile(f, 'utf8');
371	      out.push({ id: itemId(f), provider, scope, filePath: f, title: path.basename(f), meta: {}, content: raw });
372	    } catch {
373	      /* absent — skip */
374	    }
375	  }
376	  return out;
377	}
378	
379	/** Parse hooks out of a settings.json-shaped file: { hooks: { <Event>: [{matcher, hooks:[{command}]}] } }.
380	 *  Malformed JSON -> single parseError item (listed, never thrown/omitted). Missing file -> []. */
381	export async function scanHooksJson(
382	  filePath: string,
383	  provider: 'claude' | 'codex',
384	  scope: 'global' | 'project',
385	): Promise<CustomizationItem[]> {
386	  let raw: string;
387	  try {
388	    raw = await readFile(filePath, 'utf8');
389	  } catch {
390	    return [];
391	  }
392	  let parsed: any;
393	  try {
394	    parsed = JSON.parse(raw);
395	  } catch (e) {
396	    return [{ id: itemId(filePath), provider, scope, filePath, title: path.basename(filePath), meta: {}, content: raw, parseError: e instanceof Error ? e.message : 'invalid JSON' }];
397	  }
398	  const out: CustomizationItem[] = [];
399	  const hooks = parsed?.hooks && typeof parsed.hooks === 'object' ? parsed.hooks : {};
400	  for (const [event, entries] of Object.entries<any>(hooks)) {
401	    if (!Array.isArray(entries)) continue;
402	    entries.forEach((entry, i) => {
403	      const cmds = Array.isArray(entry?.hooks) ? entry.hooks : [];
404	      cmds.forEach((h: any, j: number) => {
405	        const key = `${event}[${i}][${j}]`;
406	        out.push({
407	          id: itemId(filePath, key),
408	          provider,
409	          scope,
410	          filePath,
411	          title: event,
412	          meta: { event, matcher: String(entry?.matcher ?? ''), command: String(h?.command ?? '') },
413	          content: JSON.stringify(entry, null, 2),
414	        });
415	      });
416	    });
417	  }
418	  return out;
419	}
420	
421	/** Parse MCP servers from a .mcp.json-shaped file: { mcpServers: { <name>: {command, args?} } }. */
422	export async function scanMcpJson(
423	  filePath: string,
424	  provider: 'claude' | 'codex',
425	  scope: 'global' | 'project',
426	): Promise<CustomizationItem[]> {
427	  let raw: string;
428	  try {
429	    raw = await readFile(filePath, 'utf8');
430	  } catch {
431	    return [];
432	  }
433	  let parsed: any;
434	  try {
435	    parsed = JSON.parse(raw);
436	  } catch (e) {
437	    return [{ id: itemId(filePath), provider, scope, filePath, title: path.basename(filePath), meta: {}, content: raw, parseError: e instanceof Error ? e.message : 'invalid JSON' }];
438	  }
439	  const servers = parsed?.mcpServers && typeof parsed.mcpServers === 'object' ? parsed.mcpServers : {};
440	  return Object.entries<any>(servers).map(([name, cfg]) => ({
441	    id: itemId(filePath, name),
442	    provider,
443	    scope,
444	    filePath,
445	    title: name,
446	    meta: { command: [cfg?.command, ...(Array.isArray(cfg?.args) ? cfg.args : [])].filter(Boolean).join(' ') },
447	    content: JSON.stringify(cfg, null, 2),
448	  }));
449	}
