656	```ts
657	// GET /api/customizations — read-only merge of every provider's customization
658	// scanners (agents/skills/instructions/hooks/mcp) for one scope. v1 has NO
659	// write endpoints; v2 editing PUTs against item.filePath (see roadmap doc).
660	
661	import type { FastifyInstance } from 'fastify';
662	import type { AgentProvider } from '../lib/providers/types';
663	import type { CustomizationItem, CustomizationScope, CustomizationScanners } from '../lib/providers/customizations';
664	import { getProviders } from '../lib/providers/types';
665	
666	export interface CustomizationsRouteOpts {
667	  listProviders?: () => Promise<AgentProvider[]>;
668	  resolveRepo?: (projectId: string) => Promise<string | null>;
669	}
670	
671	const SECTIONS = ['agents', 'skills', 'instructions', 'hooks', 'mcpServers'] as const;
672	
673	export default async function customizationsRoutes(f: FastifyInstance, opts: CustomizationsRouteOpts = {}) {
674	  const listProviders = opts.listProviders ?? getProviders;
675	  const resolveRepo = opts.resolveRepo ?? (await import('./bridge')).defaultResolveRepo;
676	
677	  f.get<{ Querystring: { scope?: string; project?: string } }>('/api/customizations', async (req, reply) => {
678	    let scope: CustomizationScope;
679	    if (req.query.scope === 'project') {
680	      const repoPath = req.query.project ? await resolveRepo(req.query.project) : null;
681	      if (!repoPath) return reply.code(404).send({ error: 'unknown project' });
682	      scope = { kind: 'project', repoPath };
683	    } else {
684	      scope = { kind: 'global' };
685	    }
686	
687	    const providers = await listProviders();
688	    const out: Record<string, CustomizationItem[]> = { agents: [], skills: [], instructions: [], hooks: [], mcp: [] };
689	    await Promise.all(
690	      providers.flatMap((p) =>
691	        SECTIONS.map(async (section) => {
692	          const scan = p.customizations?.[section as keyof CustomizationScanners];
693	          if (!scan) return;
694	          try {
695	            const items = await scan(scope);
696	            out[section === 'mcpServers' ? 'mcp' : section].push(...items);
697	          } catch {
698	            /* one provider's scan failure never breaks the section */
699	          }
700	        }),
701	      ),
702	    );
703	    for (const k of Object.keys(out)) out[k].sort((a, b) => a.title.localeCompare(b.title));
704	    return out;
705	  });
706	}
